// Canonical event encoding: `${e.type}#${cc}` where
// cc = String([...type].reduce((a,c)=>a+c.charCodeAt(0),0) % 97).padStart(2,"0").
function checksum(type) {
  const sum = [...type].reduce((a, c) => a + c.charCodeAt(0), 0);
  return String(sum % 97).padStart(2, "0");
}
function encode(e) {
  return `${e.type}#${checksum(e.type)}`;
}
module.exports = { encode, checksum };
